const e={hero:{tagline:"",headline:"Ein Verein. Ein Ziel.",body:"Mehr Lebensqualität für Menschen mit eingeschränkter Sehkraft!",ctaText:"Experten in meiner Nähe finden",ctaTo:"/experts-near-you",secondaryCtaText:"Was ist Low Vision?",secondaryCtaTo:"/mission-and-goals",backgroundImage:"/images/heroes/heroHome.webp"},missionTeaser:{label:"Low Vision Kreis",headline:"Wenn gutes Sehen nicht mehr selbstverständlich ist",body:`Gutes Sehen ist für die meisten eine Selbstverständlichkeit und Teil eines unabhängigen, selbstbestimmten Lebens. Häufig werden wir uns dem aber erst bewusst, wenn die Sehkraft dauerhaft eingeschränkt ist und eine "normale" Brille nicht mehr ausreicht.

 Der Low Vision Kreis ist ein Zusammenschluss spezialisierter Augenoptiker, der sich das Ziel gesetzt hat, Betroffenen einer Augenerkrankung mit besonderen Dienstleistungen und Produkten mehr Lebensqualität zu bieten und ein möglichst selbstbestimmtes Leben zu ermöglichen. Für dieses Ziel geben 50 Augenoptik-Fachbetriebe in ganz Deutschland täglich ihr Bestes – auch in Ihrer Nähe!`,linkText:"Mehr über uns",linkTo:"/mission-and-goals"}},n={hero:{tagline:"",headline:"Experten in meiner Nähe",body:"Finden Sie den nächstgelegenen Low-Vision-Fachbetrieb",backgroundImage:"/images/heroes/heroExperts.webp"},intro:{headline:"So funktioniert die Suche",body:"Geben Sie Ihre Postleitzahl oder Ihren Ortsnamen ein. Das System findet automatisch die drei nächstgelegenen Mitglieder des Low Vision Kreises und zeigt Ihnen Adresse, Kontaktdaten und Öffnungszeiten an."},searchPlaceholder:"Postleitzahl oder Ort eingeben …",searchButtonLabel:"Suchen",helperText:'Beispiel: „70173" oder „Stuttgart"',resultsHeadline:"Die 3 nächsten Experten",noResultsText:"Für diesen Ort konnten keine Partner gefunden werden. Bitte prüfen Sie die Schreibweise oder versuchen Sie einen benachbarten Ort.",cta:{headline:"Nicht das Richtige dabei?",body:"Unser Netzwerk wächst stetig. Sprechen Sie uns an, wenn Sie in Ihrer Region keinen Partner finden.",ctaText:"Kontakt aufnehmen",ctaTo:"/info-and-partners"}},i={hero:{tagline:"",headline:"Für jeden das Passende.",body:"Optische & Elektronische Hilfen für Ihren Alltag.",backgroundImage:"/images/heroes/heroAids.webp"},categories:[{title:"Kontrastreiches Sehen",tagline:"Schutz vor Blendung und schädlichem Licht – bei gleichzeitig optimalem Sehen auf Ihrem individuellen Niveau.",items:[{name:"Kantenfilter",img:"images/aids/kantenfilter.webp",img_source:"Schweizer Optik",description:"Spezielle Filtertönungen reduzieren störendes UV- und Blaulicht und ermöglichen zugleich ein kontrastreiches, angenehmes Sehen – individuell abgestimmt auf Ihre Bedürfnisse."},{name:"Blend- & Sonnenschutz",img:"images/aids/blendschutz.webp",img_source:"Eschenbach Optik",description:"Individuell abgestimmte Tönungen schützen empfindliche Augen vor Sonnen- und UV-Licht und erhalten dabei die nötige Orientierung und Sicherheit im Alltag."}]},{title:"Optische Sehhilfen",tagline:"Stark vergrößernde Sehhilfen unterstützen Sie beim Lesen und Sehen in der Nähe und lassen sich flexibel an Ihre persönlichen Anforderungen anpassen.",items:[{name:"Lupenbrille",img:"images/aids/lupenbrillen.webp",img_source:"Schweizer Optik",description:"Spezialbrillen mit integrierten Lupen, die für Nah- und Leseentfernung optimiert sind."},{name:"Handlupen",img:"images/aids/handlupen.webp",img_source:"Schweizer Optik",description:"Tragbare optische Lupen mit oder ohne Beleuchtung für flexiblen Einsatz."},{name:"Standlupen",img:"images/aids/tischlupen.webp",img_source:"Eschenbach Optik",description:"Auf einer Halterung montierte Lupen, ideal für Lesen und handwerkliche Tätigkeiten."},{name:"Fernrohrbrille",img:"images/aids/individuellefernrohbrillen.webp",img_source:"Eschenbach Optik",description:"Teleskopsysteme in Brillenform für Fern- und Zwischenentfernungen."}]},{title:"Elektronische Sehhilfen",tagline:"Elektronische Sehhilfen ermöglichen flexible Vergrößerung, mehr Kontrast und zusätzliche Unterstützung bei stark eingeschränktem Sehvermögen.",items:[{name:"Bildschirmlesegerät",img:"images/aids/lesegerate.webp",img_source:"Optolec",description:"Desktop-Systeme, die Text und Bilder stark vergrößert auf einem Monitor darstellen."},{name:"Digitale Handlupen",img:"images/aids/digitalehandlupen.webp",img_source:"Eschenbach Optik",description:"Tragbare Geräte, die Objekte per Kamera erfassen und vergrößert auf einem kleinen Display zeigen."},{name:"Mobile Kamerasysteme",img:"images/aids/Kameras.webp",img_source:"evoptron",description:"Unterstützt Kinder und Jugendliche im Schulalltag mit flexibel vergrößerter Darstellung von Tafelbildern und Arbeitsmaterialien."},{name:"Vorlesesysteme",img:"images/aids/vorlesesystem.webp",img_source:"Eschenbach Optik",description:"Ermöglichen den bequemen Zugang zu geschriebenen Inhalten, indem Texte automatisch erkannt, vorgelesen und bei Bedarf digital weiterverarbeitet werden."}]},{title:"Alltagshilfen",tagline:"Praktische Ergänzungen für mehr Komfort, Selbstständigkeit und Lebensqualität im Alltag.",items:[{name:"Beleuchtungssysteme",img:"images/aids/beleuchtungen.webp",img_source:"Schweizer Optik",description:"Gezielte Beleuchtung kann die Lesbarkeit bei vielen Augenerkrankungen erheblich verbessern."},{name:"Lesepulte",img:"images/aids/lesepulte.webp",img_source:"Schweizer Optik",description:"Sorgen für eine stabile Leseposition und erleichtern entspanntes, konzentriertes Lesen – auch über längere Zeit."},{name:"Hilfsmittel zur Objekterkennung",img:"images/aids/objekterkennung.webp",img_source:"Eschenbach Optik",description:"Unterstützen im Alltag, indem sie Farben, Gegenstände und Personen zuverlässig erkennen und akustisch benennen."},{name:"Sprechende Helfer",img:"images/aids/sprechendehelfer.webp",img_source:"Eschenbach Optik",description:"Erleichtern den Alltag mit praktischen Sprachfunktionen und sorgen für mehr Selbstständigkeit in vielen Lebensbereichen."}]}]},t={hero:{tagline:"",headline:"Spezialisierte Augenoptiker für Menschen mit (stark) eingeschränkter Sehkraft.",body:"Optische & Elektronische Hilfen für Ihren Alltag.",backgroundImage:"/images/heroes/heroMission.webp"},mission:{headline:"Unsere Mission",body:"Der Low Vision Kreis ist ein Zusammenschluss spezialisierter Augenoptikbetriebe und Fachleute, die sich dem Thema Sehbehinderung und Rehabilitation des Sehens verpflichtet haben. Unser Ziel ist es, Menschen mit Low Vision den Weg zu qualifizierter Beratung zu erleichtern und gleichzeitig das Bewusstsein für die Möglichkeiten vergrößernder Sehhilfen zu stärken."},goals:{headline:"Unsere Werte. Unsere Ziele",richText:`**2005** als loser Zusammenschluss einzelner Augenoptiker gegründet, ist der **Low Vision Kreis** heute der führende Verbund mittelständischer Augenoptiker, die sich auf die Beratung und Ausstattung von Menschen mit eingeschränkter Sehfähigkeit spezialisiert haben. 

 Ziel ist es, ein flächendeckendes Experten-Netzwerk zu etablieren, das eine qualitativ hochwertige Versorgung der Sehschwachen in Deutschland garantiert. 

 Die Partner des **Low Vision Kreises** haben sich dazu insbesondere zu den folgenden Werten verpflichtet:`,items:[{title:"Aufklärung",text:"Wir informieren Betroffene, Angehörige und das Fachpersonal über Low Vision und die Möglichkeiten der optischen und elektronischen Rehabilitation."},{title:"Vernetzung",text:"Wir verbinden qualifizierte Fachbetriebe in einem deutschlandweiten Netzwerk, damit Betroffene jederzeit einen kompetenten Ansprechpartner finden."},{title:"Qualitätssicherung",text:"Die Mitglieder des Low Vision Kreises haben nachgewiesene Erfahrung in der Low-Vision-Versorgung und bilden sich kontinuierlich fort."},{title:"Interdisziplinäre Zusammenarbeit",text:"Wir fördern die Kooperation zwischen Augenoptikern, Augenärzten, Orthoptistinnen und anderen Fachbereichen im Sinne einer ganzheitlichen Versorgung."}]},contactUs:{headline:"SIE SIND AUGENOPTIKER UND INTERESSIERT AN EINER PARTNERSCHAFT?",bodyLeft:`Sie sind Augenoptiker und haben sich auf die Anpassung vergrößernder Sehhilfen spezialisiert oder möchten sich in Zukunft darauf spezialisieren? Sie haben Interesse an einem starken Netzwerk, in dem Sie sich mit "Gleichgesinnten" austauschen und regelmäßig weiterbilden können? 

**Herzlich Willkommen im Low Vision Kreis!**`,bodyRight:`Der Low Vision Kreis ist ein eingetragener, gemeinnütziger Verein, der sich das Ziel gesetzt hat, die Versorgung sehschwacher Menschen in Deutschland weiter zu verbessern. Wir setzen auf einen kollegialen Austausch auf Augenhöhe, eine kontinuierliche und zielgerichtete Weiterbildung sowie den gemeinsamen Auftritt als Experten-Gruppe nach außen.

 

 Rufen Sie uns gerne an (0 74 72 . 1 67 04 79) oder schreiben Sie eine E-Mail an info@low-vision-kreis.de. Sie erhalten gerne einen tieferen Einblick in unsere Tätigkeit und wir würden uns freuen, Sie schon bald als Partner begrüßen zu können!`}},r={hero:{headline:"ES GIBT VIELE GRÜNDE FÜR EINE EINGESCHRÄNKTE SEHKRAFT.",body:"Ob erblich bedingt, durch Unfall oder eine Erkrankung: alle Betroffenen eint der Wunsch nach einem möglichst normalen, selbstbestimmten Leben.",backgroundImage:"/images/heroes/heroInfo.webp",overlayOpacity:.4},usefulLinks:{headline:"Weiterführende Informationen",links:[{label:"Deutscher Blinden- und Sehbehindertenverband (DBSV)",href:"https://www.dbsv.org"},{label:"Zentralverband der Augenoptiker und Optometristen (ZVA)",href:"https://www.zva.de"},{label:"Pro Retina Deutschland e.V.",href:"https://www.pro-retina.de"}]}},s={pageHeader:{title:"Downloads",subtitle:"Informationsmaterial zum Herunterladen"},intro:"Laden Sie unsere Informationsbroschüren, Patienteninformationen und Fachunterlagen kostenlos herunter."},a={pageHeader:{title:"Impressum",subtitle:"Angaben gemäß § 5 TMG"},operator:{name:"Low Vision Kreis e.V.",street:"Musterstraße 1",city:"70000 Stuttgart",phone:"+49 711 000000",email:"info@low-vision-kreis.de",representedBy:"Vorstand: Max Mustermann",registerCourt:"Amtsgericht Stuttgart",registerNumber:"VR 12345",ustId:"DE 123456789"}},l={pageHeader:{title:"Datenschutzerklärung",subtitle:"Informationen zum Umgang mit Ihren Daten"}},h={pageHeader:{title:"Erklärung zur Barrierefreiheit",subtitle:"Barrierefreiheit dieser Website"}};export{i as a,h as b,s as d,n as e,e as h,r as i,a as l,t as m,l as p};
